    case 4:
      if (lookahead == 'y') ADVANCE(6);
      END_STATE();
    case 5:
      if (lookahead == 'q') ADVANCE(7);
      END_STATE();
    case 6:
      if (lookahead == 'b') ADVANCE(8);
      END_STATE();
    case 7:
      if (lookahead == 'u') ADVANCE(9);
      END_STATE();
    case 8:
      if (lookahead == 'e') ADVANCE(10);
      END_STATE();
    case 9:
